	result.start = start;
	result.end = end;
	result.step = step;
	if (Math.sign(step) !== Math.sign(end - start)) return result;
	if (step > 0) for (let i = start; i < end; i += step) result.push(i);
	if (step < 0) for (let i = start; i > end; i += step) result.push(i);
